vector<int> numbers = {2, 4, 1, 7, 3, 6};

// "What's the sum from index 1 to 4?" — naive: loop through indices 1-4 each time, O(n) PER query
// If asked 1,000 different range questions, that's O(n * 1000) total

vector<int> numbers = {2, 4, 1, 7, 3, 6};
vector<int> prefix(numbers.size());

prefix[0] = numbers[0];
for (int i = 1; i < numbers.size(); i++)
{
    prefix[i] = prefix[i - 1] + numbers[i]; // running total
}
// prefix = {2, 6, 7, 14, 17, 23}

#include <iostream>
#include <vector>

using namespace std;

int main()
{
    vector<int> numbers = {2, 4, 1, 7, 3, 6};
    vector<int> prefix(numbers.size());

    prefix[0] = numbers[0];
    for (int i = 1; i < numbers.size(); i++)
    {
        prefix[i] = prefix[i - 1] + numbers[i];
    }

    int l = 1, r = 4;
    int rangeSum = (l == 0) ? prefix[r] : prefix[r] - prefix[l - 1];

    cout << rangeSum << endl;

    return 0;
}

