#include <vector>

using namespace std;

class NumArray {
public:
    vector<int> nums;

    NumArray(vector<int> &input) { nums = input; }

    int sumRange(int left, int right)
    {
        int sum = 0;
        for (int i = left; i <= right; i++) sum += nums[i];
        return sum;
    }
};

int main()
{
    vector<int> nums = {-2, 0, 3, -5, 2, -1};
    NumArray obj(nums);

    cout << obj.sumRange(0, 2) << " " << obj.sumRange(2, 5) << " " << obj.sumRange(0, 5) << endl;

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

class NumArray {
public:
    vector<int> prefix;

    NumArray(vector<int> &nums)
    {
        prefix.resize(nums.size());
        prefix[0] = nums[0];
        for (int i = 1; i < nums.size(); i++) prefix[i] = prefix[i - 1] + nums[i];
    }

    int sumRange(int left, int right)
    {
        return (left == 0) ? prefix[right] : prefix[right] - prefix[left - 1];
    }
};

int main()
{
    vector<int> nums = {-2, 0, 3, -5, 2, -1};
    NumArray obj(nums);

    cout << obj.sumRange(0, 2) << " " << obj.sumRange(2, 5) << " " << obj.sumRange(0, 5) << endl;

    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

class NumArray {
public:
    vector<int> prefix;

    NumArray(vector<int> &nums)
    {
        prefix.assign(nums.size() + 1, 0);
        for (int i = 0; i < nums.size(); i++) prefix[i + 1] = prefix[i] + nums[i];
    }

    int sumRange(int left, int right)
    {
        return prefix[right + 1] - prefix[left];
    }
};

int main()
{
    vector<int> nums = {-2, 0, 3, -5, 2, -1};
    NumArray obj(nums);

    cout << obj.sumRange(0, 2) << " " << obj.sumRange(2, 5) << " " << obj.sumRange(0, 5) << endl;

    return 0;
}

